import React, { useEffect, useState, useCallback } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import Header from '../components/Header';
import Footer from '../components/Footer';
import { useCart } from '../context/CartContext';
import './Shop.css';
import './Swimwear.css';

// Featured product with real images
const FEATURED_PRODUCT = {
  id: 'queen-swimsuit',
  slug: 'queen',
  name: 'Queen',
  price: 450,
  compare_at_price: null,
  main_image_url: '/images/su1.jpeg',
  images: [
    { id: 1, image_url: '/su1.jpeg', label: 'Front' },
    { id: 2, image_url: '/su2.jpeg', label: 'Back'  },
    { id: 3, image_url: '/su3.jpeg', label: 'Side'  },
  ],
  description: 'A boldly feminine swimsuit designed to turn heads. The Queen set features a triangle top with adjustable ties and matching high-cut bikini bottoms — crafted to flatter every curve.',
  fabric_care: '80% Nylon, 20% Elastane. Rinse in cold water after each use. Do not bleach or tumble dry.',
  sizing_fit: 'Runs true to size. Model wears a size M. We recommend sizing up for a more relaxed fit.',
  is_featured: true,
};

const SIZES = ['XS', 'S', 'M', 'L', 'XL', 'XXL'];
const OUT_OF_STOCK = ['XXL'];

export default function Swimwear() {
  const { addToCart } = useCart();
  const navigate = useNavigate();

  // Gallery state
  const [activeImg, setActiveImg]   = useState(0);
  const [selSize, setSelSize]       = useState('');
  const [qty, setQty]               = useState(1);
  const [wishlisted, setWishlisted] = useState(false);
  const [added, setAdded]           = useState(false);
  const [sizeError, setSizeError]   = useState(false);
  const [openAcc, setOpenAcc]       = useState('description');
  const [notifyOpen, setNotifyOpen] = useState(false);
  const [zoomed, setZoomed]         = useState(false);

  // Other swimwear products from API
  const [otherProducts, setOtherProducts] = useState([]);

  useEffect(() => {
    fetch('/api/products/?category__slug=swimwear')
      .then(r => r.json())
      .then(d => {
        const all = d.results || d;
        setOtherProducts(all.filter(p => p.slug !== 'queen').slice(0, 8));
      })
      .catch(() => {});
  }, []);

  const handleAddToBag = () => {
    if (!selSize) {
      setSizeError(true);
      setTimeout(() => setSizeError(false), 2000);
      return;
    }
    addToCart(FEATURED_PRODUCT, selSize, '', qty);
    setAdded(true);
    setTimeout(() => setAdded(false), 2200);
  };

  const toggleAcc = (key) => setOpenAcc(v => v === key ? '' : key);

  const accSections = [
    { key: 'description', label: 'Description',      body: FEATURED_PRODUCT.description },
    { key: 'fabric',      label: 'Fabric & Care',    body: FEATURED_PRODUCT.fabric_care },
    { key: 'sizing',      label: 'Sizing & Fit',     body: FEATURED_PRODUCT.sizing_fit },
    { key: 'delivery',    label: 'Delivery & Returns', body: 'Standard delivery R95, free on orders over R850. Delivered within 3–5 working days. Returns accepted within 30 days — unworn, tags attached.' },
  ];

  return (
    <>
      <Header />

      {/* Breadcrumb */}
      <div className="breadcrumb">
        <span className="bc" onClick={() => navigate('/')}>Home</span>
        <span className="bc-sep">›</span>
        <span className="bc cur">Swimwear</span>
      </div>

      {/* ── FEATURED PRODUCT: QUEEN ── */}
      <section className="sw-featured">

        {/* Gallery */}
        <div className="sw-gallery">
          <div className="sw-gallery__thumbs">
            {FEATURED_PRODUCT.images.map((img, i) => (
              <button
                key={img.id}
                className={`sw-thumb${activeImg === i ? ' on' : ''}`}
                onClick={() => setActiveImg(i)}
              >
                <img src={img.image_url} alt={img.label} />
                <span className="sw-thumb__label">{img.label}</span>
              </button>
            ))}
          </div>

          <div className={`sw-gallery__main${zoomed ? ' zoomed' : ''}`} onClick={() => setZoomed(v => !v)}>
            <img
              src={FEATURED_PRODUCT.images[activeImg].image_url}
              alt={`${FEATURED_PRODUCT.name} — ${FEATURED_PRODUCT.images[activeImg].label}`}
              className="sw-gallery__img"
            />
            <span className="sw-gallery__counter">
              {activeImg + 1} / {FEATURED_PRODUCT.images.length}
            </span>
            <span className="sw-gallery__zoom-hint">
              <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                <circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/>
                <line x1="11" y1="8" x2="11" y2="14"/><line x1="8" y1="11" x2="14" y2="11"/>
              </svg>
              {zoomed ? 'Click to zoom out' : 'Click to zoom'}
            </span>

            {/* Prev/Next arrows */}
            {activeImg > 0 && (
              <button className="sw-gallery__arrow sw-gallery__arrow--prev"
                onClick={e => { e.stopPropagation(); setActiveImg(i => i - 1); }}>
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                  <polyline points="15 18 9 12 15 6"/>
                </svg>
              </button>
            )}
            {activeImg < FEATURED_PRODUCT.images.length - 1 && (
              <button className="sw-gallery__arrow sw-gallery__arrow--next"
                onClick={e => { e.stopPropagation(); setActiveImg(i => i + 1); }}>
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                  <polyline points="9 18 15 12 9 6"/>
                </svg>
              </button>
            )}
          </div>
        </div>

        {/* Info panel */}
        <div className="sw-info">
          <div className="sw-info__top">
            <p className="sw-info__eyebrow">Dream In Lace · Swimwear</p>
            <button className="sw-share"
              onClick={() => navigator.share?.({ title: FEATURED_PRODUCT.name, url: window.location.href })}>
              <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.4">
                <circle cx="18" cy="5" r="3"/><circle cx="6" cy="12" r="3"/><circle cx="18" cy="19" r="3"/>
                <line x1="8.59" y1="13.51" x2="15.42" y2="17.49"/>
                <line x1="15.41" y1="6.51" x2="8.59" y2="10.49"/>
              </svg>
              Share
            </button>
          </div>

          <h1 className="sw-info__name">{FEATURED_PRODUCT.name}</h1>

          {/* Stars */}
          <div className="sw-rating">
            {[1,2,3,4,5].map(s => (
              <svg key={s} width="13" height="13" viewBox="0 0 24 24"
                fill={s <= 5 ? '#b8a08a' : 'none'} stroke="#b8a08a" strokeWidth="1">
                <polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"/>
              </svg>
            ))}
            <span className="sw-rating__count">18 reviews</span>
          </div>

          {/* Price */}
          <div className="sw-price-row">
            <span className="sw-price">R {FEATURED_PRODUCT.price.toLocaleString()}</span>
          </div>

          {/* View labels */}
          <div className="sw-view-pills">
            {FEATURED_PRODUCT.images.map((img, i) => (
              <button
                key={img.id}
                className={`sw-view-pill${activeImg === i ? ' on' : ''}`}
                onClick={() => setActiveImg(i)}
              >
                {img.label} view
              </button>
            ))}
          </div>

          {/* Size */}
          <div className={`sw-field-label${sizeError ? ' error' : ''}`}>
            Size {selSize && <span>{selSize}</span>}
            {sizeError && <span className="sw-size-error">Please select a size</span>}
          </div>
          <div className="sw-sizes">
            {SIZES.map(s => {
              const out = OUT_OF_STOCK.includes(s);
              return (
                <button
                  key={s}
                  className={`sw-sz${selSize === s ? ' on' : ''}${out ? ' out' : ''}`}
                  onClick={() => out ? setNotifyOpen(true) : setSelSize(s)}
                >{s}</button>
              );
            })}
          </div>
          <button className="sw-size-guide">Size guide →</button>

          {/* Qty */}
          <div className="sw-field-label" style={{ marginBottom: '.5rem' }}>Quantity</div>
          <div className="sw-qty">
            <button className="sw-qty__btn" onClick={() => setQty(v => Math.max(1, v - 1))}>−</button>
            <span className="sw-qty__val">{qty}</span>
            <button className="sw-qty__btn" onClick={() => setQty(v => v + 1)}>+</button>
          </div>

          {/* CTA */}
          <div className="sw-cta">
            <button className={`sw-add-btn${added ? ' added' : ''}`} onClick={handleAddToBag}>
              {added ? 'Added to Bag ✓' : 'Add to Bag'}
            </button>
            <button
              className={`sw-wish-btn${wishlisted ? ' on' : ''}`}
              onClick={() => setWishlisted(v => !v)}
              aria-label="Wishlist"
            >
              <svg width="18" height="18" viewBox="0 0 24 24"
                fill={wishlisted ? 'currentColor' : 'none'}
                stroke="currentColor" strokeWidth="1.4">
                <path d="M20.84 4.61a5.5 5.5 0 00-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 00-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 000-7.78z"/>
              </svg>
            </button>
          </div>

          {/* Trust strip */}
          <div className="sw-trust">
            {[
              { icon: 'M5 12h14M12 5l7 7-7 7', t: 'Free delivery', s: 'Over R850' },
              { icon: 'M23 4 23 10 17 10M20.49 15a9 9 0 11-2.12-9.36L23 10', t: '30-day returns', s: 'Easy & free' },
              { icon: 'M3 11h18v11H3zM7 11V7a5 5 0 0110 0v4', t: 'Secure checkout', s: 'SSL encrypted' },
            ].map(u => (
              <div className="sw-trust__item" key={u.t}>
                <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.3">
                  <path d={u.icon}/>
                </svg>
                <div>
                  <p className="sw-trust__title">{u.t}</p>
                  <p className="sw-trust__sub">{u.s}</p>
                </div>
              </div>
            ))}
          </div>

          {/* Accordion */}
          <div className="sw-accordion">
            {accSections.map(({ key, label, body }) => (
              <div className="sw-acc__row" key={key}>
                <button
                  className={`sw-acc__head${openAcc === key ? ' open' : ''}`}
                  onClick={() => toggleAcc(key)}
                >
                  {label}
                  <svg width="13" height="13" viewBox="0 0 24 24" fill="none"
                    stroke="currentColor" strokeWidth="1.5"
                    style={{ transition: 'transform .25s', transform: openAcc === key ? 'rotate(180deg)' : 'none', flexShrink: 0 }}>
                    <polyline points="6 9 12 15 18 9"/>
                  </svg>
                </button>
                {openAcc === key && <div className="sw-acc__body">{body}</div>}
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ── MORE SWIMWEAR ── */}
      {otherProducts.length > 0 && (
        <section className="sw-more">
          <div className="page-inner">
            <div className="section-header">
              <h2 className="section-title">More Swimwear</h2>
              <Link to="/swimwear" className="section-link">View all</Link>
            </div>
            <div className="sw-more__grid">
              {otherProducts.map(p => (
                <Link to={`/products/${p.slug}`} key={p.id} className="sw-more__card">
                  <div className="sw-more__card-img">
                    {p.main_image_url
                      ? <img src={p.main_image_url} alt={p.name} loading="lazy" />
                      : <div className="sw-more__card-ph">{p.name}</div>
                    }
                  </div>
                  <div className="sw-more__card-info">
                    <p className="sw-more__card-name">{p.name}</p>
                    <p className="sw-more__card-price">R {parseFloat(p.price).toLocaleString()}</p>
                  </div>
                </Link>
              ))}
            </div>
          </div>
        </section>
      )}

      {/* Notify me modal */}
      {notifyOpen && (
        <div className="sw-modal-overlay" onClick={() => setNotifyOpen(false)}>
          <div className="sw-modal" onClick={e => e.stopPropagation()}>
            <h2 className="sw-modal__title">Notify me</h2>
            <p className="sw-modal__sub">Enter your email and we'll let you know when this size is back.</p>
            <input className="field__input" type="email" placeholder="your@email.com" />
            <button className="btn-primary" style={{ width: '100%', marginTop: 10 }}
              onClick={() => setNotifyOpen(false)}>Notify Me</button>
            <button className="sw-modal__close" onClick={() => setNotifyOpen(false)}>Cancel</button>
          </div>
        </div>
      )}

      <Footer />
    </>
  );
}
